using System.Text.RegularExpressions;

namespace Contoso.Text;

public sealed class StringFormatter
{
    public string FormatPhoneNumber(string digits)
    {
        ArgumentNullException.ThrowIfNull(digits);
        if (digits.Length != 10)
            throw new ArgumentException("Must be exactly 10 digits.", nameof(digits));
        return $"({digits[..3]}) {digits[3..6]}-{digits[6..]}";
    }

    public string BuildGreeting(string name, string title = "Mr.")
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(name);
        return $"Dear {title} {name},";
    }

    public string GenerateSlug(string title)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(title);
        return Regex.Replace(title.Trim().ToLowerInvariant(), @"[^a-z0-9]+", "-").Trim('-');
    }

    public string FormatCurrency(decimal amount, string symbol = "$")
    {
        return $"{symbol}{amount:F2}";
    }
}

using System.Text.RegularExpressions;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ────────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        string result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_StartsWithAreaCode()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith(result, "(555)");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_EndsWithLastFourDigits()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith(result, "4567");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_ContainsDash()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_MatchesPattern()
    {
        string result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_TooFewDigits_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber("12345"));
    }

    [TestMethod]
    public void FormatPhoneNumber_TooManyDigits_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber("12345678901"));
    }

    // ── BuildGreeting ────────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsFullGreeting()
    {
        string result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_Result_StartsWithDear()
    {
        string result = _formatter.BuildGreeting("Doe", "Dr.");

        Assert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_Result_EndsWithComma()
    {
        string result = _formatter.BuildGreeting("Doe", "Dr.");

        Assert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_Result_ContainsName()
    {
        string result = _formatter.BuildGreeting("Doe", "Dr.");

        Assert.Contains(result, "Doe");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_IncludesTitle()
    {
        string result = _formatter.BuildGreeting("Doe", "Prof.");

        Assert.StartsWith(result, "Dear Prof.");
    }

    [TestMethod]
    public void BuildGreeting_NullName_Throws()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting("   "));
    }

    // ── GenerateSlug ─────────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        string result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_Result_DoesNotStartWithDash()
    {
        string result = _formatter.GenerateSlug("  --Hello!  ");

        Assert.DoesNotStartWith(result, "-");
    }

    [TestMethod]
    public void GenerateSlug_Result_DoesNotEndWithDash()
    {
        string result = _formatter.GenerateSlug("  Hello--  ");

        Assert.DoesNotEndWith(result, "-");
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        string result = _formatter.GenerateSlug("My Article Title!!");

        Assert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_CollapsesToSingleDash()
    {
        string result = _formatter.GenerateSlug("A & B");

        Assert.AreEqual("a-b", result);
    }

    [TestMethod]
    public void GenerateSlug_NullInput_Throws()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.GenerateSlug(null!));
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceInput_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

    // ── FormatCurrency ───────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ReturnsDollarFormat()
    {
        string result = _formatter.FormatCurrency(19.99m);

        Assert.AreEqual("$19.99", result);
    }

    [TestMethod]
    public void FormatCurrency_Result_StartsWithSymbol()
    {
        string result = _formatter.FormatCurrency(10m, "€");

        Assert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_Result_ContainsDecimalPoint()
    {
        string result = _formatter.FormatCurrency(5m);

        Assert.Contains(result, ".");
    }

    [TestMethod]
    public void FormatCurrency_Result_EndsWithTwoDecimalPlaces()
    {
        string result = _formatter.FormatCurrency(5m);

        Assert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_Result_MatchesCurrencyPattern()
    {
        string result = _formatter.FormatCurrency(1234.5m, "£");

        Assert.Matches(result, new Regex(@"^£\d+\.\d{2}$"));
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_StartsWithSymbolAndMinus()
    {
        string result = _formatter.FormatCurrency(-5.50m);

        Assert.StartsWith(result, "$-");
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsZeroFormatted()
    {
        string result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

